import path from 'tjs:path';
import assert from 'tjs:assert';

const tmpDir = await tjs.makeTempDir(path.join(tjs.tmpDir, 'test_dirXXXXXX'));

async function sleep(ms) {
    return new Promise(resolve => {
        setTimeout(resolve, ms);
    });
}

// Test 1: Watcher without a variable reference should still work
let callbackFired = false;
tjs.watch(tmpDir, (filename, event) => {
    callbackFired = true;
    console.log('GC-SAFE WATCHER FIRED:', filename, event);
});

await sleep(500);

// Trigger file system events
const f = await tjs.makeTempFile(path.join(tmpDir, 'test_fileXXXXXX'));
await sleep(500);
await f.write(new TextEncoder().encode('hello'));
await f.close();
await sleep(500);

assert.ok(callbackFired, 'FileWatcher callback should have been called');
console.log('Test 1 PASSED: FileWatcher without variable reference survived and fired callback');

// Test 2: Watcher with variable reference still works after GC
callbackFired = false;
const watcher = tjs.watch(tmpDir, (filename, event) => {
    callbackFired = true;
    console.log('REF WATCHER FIRED:', filename, event);
});

await sleep(500);

const f2 = await tjs.makeTempFile(path.join(tmpDir, 'test_file2XXXXXX'));
await sleep(500);
await f2.write(new TextEncoder().encode('world'));
await f2.close();
await sleep(500);

assert.ok(callbackFired, 'FileWatcher with variable reference should have been called');
console.log('Test 2 PASSED: FileWatcher with variable reference works as expected');

// Cleanup
watcher.close();
await tjs.remove(tmpDir);
console.log('ALL TESTS PASSED');
SCRIPT
echo "Test script created"

